private boolean isSafeReplacement(Node node, Node replacement) {
  // No checks are needed for simple names.
  if (node.isName()) {
    return true;
  }
  Preconditions.checkArgument(node.isGetProp());

  // Check all children in the property access chain
  Node current = node.getFirstChild();
  while (current != null && current.isGetProp()) {
    if (current.isName() && isNameAssignedTo(current.getString(), replacement)) {
      return false;
    }
    current = current.getFirstChild();
  }

  // Check the final base name
  if (current != null && current.isName() && isNameAssignedTo(current.getString(), replacement)) {
    return false;
  }

  return true;
}

