public String absUrl(String attributeKey) {
    Validate.notEmpty(attributeKey);

    String relUrl = attr(attributeKey);
    if (!hasAttr(attributeKey)) {
        return ""; // nothing to make absolute with
    } else {
        URL base;
        try {
            try {
                base = new URL(baseUri);
            } catch (MalformedURLException e) {
                // the base is unsuitable, but the attribute may be abs on its own, so try that
                URL abs = new URL(relUrl);
                return abs.toExternalForm();
            }

            // Handle relative URLs that start with '?' by appending to the base path
            if (relUrl.startsWith("?")) {
                String basePath = base.getPath();
                if (basePath == null || basePath.isEmpty()) {
                    basePath = "/";
                }
                // Remove any existing query string from base URL
                int queryIndex = basePath.indexOf('?');
                if (queryIndex >= 0) {
                    basePath = basePath.substring(0, queryIndex);
                }
                relUrl = basePath + relUrl;
            }

            URL abs = new URL(base, relUrl);
            return abs.toExternalForm();
        } catch (MalformedURLException e) {
            return "";
        }
    }
}

