private void findCalledFunctions(
    Node node, Set<String> changed) {
  Preconditions.checkArgument(changed != null);
  // For each referenced function, add a new reference
  if (node.getType() == Token.CALL) {
    Node child = node.getFirstChild();
    if (child.getType() == Token.NAME) {
      changed.add(child.getString());
    } else if (child.getType() == Token.GETPROP) {
      // Handle method calls like obj.method()
      Node functionNameNode = child.getFirstChild().getNext();
      if (functionNameNode != null && functionNameNode.getType() == Token.STRING) {
        changed.add(functionNameNode.getString());
      }
    }
  }

  for (Node c = node.getFirstChild(); c != null; c = c.getNext()) {
    findCalledFunctions(c, changed);
  }
}

private void findCalledFunctions(
    Node node, Set<String> changed) {
  Preconditions.checkArgument(changed != null);
  // For each referenced function, add a new reference
  if (node.getType() == Token.CALL) {
    Node child = node.getFirstChild();
    if (child.getType() == Token.NAME) {
      changed.add(child.getString());
    } else if (child.getType() == Token.GETPROP) {
      // Handle method calls like obj.method()
      Node target = child.getFirstChild();
      while (target.getNext() != null) {
        target = target.getNext();
      }
      if (target.getType() == Token.NAME) {
        changed.add(target.getString());
      }
    }
  }

  for (Node c = node.getFirstChild(); c != null; c = c.getNext()) {
    findCalledFunctions(c, changed);
  }
}

