public JsonSerializer<?> createContextual(SerializerProvider serializers,
        BeanProperty property) throws JsonMappingException
{
    if (property == null) {
        return this;
    }
    JsonFormat.Value format = findFormatOverrides(serializers, property, handledType());
    if (format == null) {
        return this;
    }
    // Simple case first: serialize as numeric timestamp?
    JsonFormat.Shape shape = format.getShape();
    if (shape.isNumeric()) {
        return withFormat(Boolean.TRUE, null);
    }

    // 08-Jun-2017, tatu: With [databind#1648], this gets bit tricky..
    // First: custom pattern will override things
    if ((shape == JsonFormat.Shape.STRING) || format.hasPattern()
            || format.hasLocale() || format.hasTimeZone()) {
        TimeZone tz = format.getTimeZone();
        DateFormat df = serializers.getConfig().getDateFormat();

        // If we have a pattern, create a new SimpleDateFormat with that pattern
        if (format.hasPattern()) {
            final Locale loc = format.hasLocale() 
                    ? format.getLocale() 
                    : serializers.getLocale();
            SimpleDateFormat sdf = new SimpleDateFormat(format.getPattern(), loc);
            if (tz == null) {
                tz = serializers.getTimeZone();
            }
            sdf.setTimeZone(tz);
            return withFormat(Boolean.FALSE, sdf);
        }

        // Otherwise, clone and configure the existing date format
        if (tz == null) {
            tz = serializers.getTimeZone();
        }
        df = (DateFormat) df.clone();
        df.setTimeZone(tz);
        if (format.hasLocale()) {
            // For StdDateFormat, we can use withLocale, otherwise we can't change locale
            if (df instanceof StdDateFormat) {
                df = ((StdDateFormat) df).withLocale(format.getLocale());
            }
            // For other DateFormat types, we can't change locale after creation
        }
        return withFormat(Boolean.FALSE, df);
    }

    return this;
}

