public String chompBalanced(char open, char close) {
    int start = -1;
    int end = -1;
    int depth = 0;
    char last = 0;
    boolean inEscape = false;

    do {
        if (isEmpty()) break;
        Character c = consume();

        if (!inEscape && c == ESC) {
            inEscape = true;
        } else {
            if (!inEscape) {
                if (c.equals(open)) {
                    depth++;
                    if (start == -1)
                        start = pos - 1; // -1 because we already consumed this char
                }
                else if (c.equals(close)) {
                    depth--;
                }
            }
            inEscape = false;
        }

        if (depth > 0 && start != -1)
            end = pos; // don't include the outer match pair in the return
        last = c;
    } while (depth > 0);

    return (start >= 0 && end >= 0) ? queue.substring(start, end) : "";
}

