{
    // If this is footer text with explicit formatting, preserve the formatting
    if (text != null && text.contains("\n")) {
        // For multi-line text, print it as-is to preserve formatting
        pw.println(text);
    } else {
        StringBuffer sb = new StringBuffer(text.length());
        renderWrappedText(sb, width, nextLineTabStop, text);
        pw.println(sb.toString());
    }
}

