public String generateToolTipFragment(String toolTipText) {
    if (toolTipText == null) {
        return " alt=\"\"";
    }
    return " title=\"" + escapeHtml(toolTipText) + "\" alt=\"\"";
}

private String escapeHtml(String text) {
    if (text == null) {
        return null;
    }
    return text.replace("&", "&amp;")
               .replace("\"", "&quot;")
               .replace("<", "&lt;")
               .replace(">", "&gt;");
}

